from itertools import count
from functools import lru_cache
from sympy import prime, integer_log, primorial, divisor_count
from oeis_sequences.OEISsequences import bisection
def A108504(n):
    if n == 1: return 1
    @lru_cache(maxsize=None)
    def g(x, m, j): return sum(g(x//(prime(m)**i), m-1, i) for i in range(j,integer_log(x, prime(m))[0]+1)) if m-1 else max(0,x.bit_length()-j)
    def f(x):
        c = n-1+x
        for k in count(1):
            if primorial(k)>x:
                break
            c -= g(x,k,1)
        return c
    return divisor_count(bisection(f,n,n))+1>>1 # _Chai Wah Wu_, Mar 24 2026

